Let's add some checks to ensure pawns cannot capture pieces directly in front of them and only capture diagonally as per the standard chess rules. Additionally, I will add logic to handle en passant captures, which is a special pawn capture move.

Here's the updated JavaScript code integrating all the mentioned features:

```javascript
const currentTurn = { color: 'white' };

function getPieceElement(row, col) {
  const cellId = String.fromCharCode('a'.charCodeAt(0) + col) + (8 - row);
  const cell = document.getElementById(cellId);
  return cell ? cell.firstChild : null;
}

function isEmpty(row, col) {
  return !getPieceElement(row, col);
}

function isEnemyPiece(row, col) {
  const piece = getPieceElement(row, col);
  if (!piece) return false;
  const isWhite = piece.id.endsWith('w');
  return (currentTurn.color === 'white' && !isWhite) || (currentTurn.color === 'black' && isWhite);
}

function canPromote(piece, toRow) {
  if (piece.id.startsWith('p')) {
    const targetRank = piece.id.endsWith('w') ? 0 : 7;
    return toRow === targetRank;
  }
  return false;
}

function calculateLegalMoves() {
  const moves = [];
  for (let row = 0; row < 8; row++) {
    for (let col = 0; col < 8; col++) {
      const piece = getPieceElement(row, col);
      if (piece && piece.id.startsWith('p') && piece.id.endsWith(currentTurn.color.charAt(0))) {
        const direction = currentTurn.color === 'white' ? -1 : 1;
        const startRow = currentTurn.color === 'white' ? 6 : 1;

        // Single step
        if (isEmpty(row + direction, col)) {
          moves.push({ from: [row, col], to: [row + direction, col] });

          // Double step
          if (row === startRow && isEmpty(row + 2 * direction, col)) {
            moves.push({ from: [row, col], to: [row + 2 * direction, col] });
          }
        }

        // Diagonal captures
        const diagLeft = col - 1;
        const diagRight = col + 1;
        if (isEnemyPiece(row + direction, diagLeft)) {
          moves.push({ from: [row, col], to: [row + direction, diagLeft] });
        }
        if (isEnemyPiece(row + direction, diagRight)) {
          moves.push({ from: [row, col], to: [row + direction, diagRight] });
        }

        // En Passant captures
        // Only possible if pawn has moved two squares last move. This will be simplified:
        // We check if the adjacent square to left/right is an enemy pawn and if the square behind that pawn is empty.
        if (currentTurn.color === 'white' && row === 3) {
          if (getPieceElement(row, diagLeft)?.id === 'p-b' && isEmpty(row - 1, diagLeft)) {
            moves.push({ from: [row, col], to: [row - 1, diagLeft], enPassant: true });
          }
          if (getPieceElement(row, diagRight)?.id === 'p-b' && isEmpty(row - 1, diagRight)) {
            moves.push({ from: [row, col], to: [row - 1, diagRight], enPassant: true });
          }
        }
        if (currentTurn.color === 'black' && row === 4) {
          if (getPieceElement(row, diagLeft)?.id === 'p-w' && isEmpty(row + 1, diagLeft)) {
            moves.push({ from: [row, col], to: [row + 1, diagLeft], enPassant: true });
          }
          if (getPieceElement(row, diagRight)?.id === 'p-w' && isEmpty(row + 1, diagRight)) {
            moves.push({ from: [row, col], to: [row + 1, diagRight], enPassant: true });
          }
        }
      }
    }
  }
  return moves;
}

function performMove(move) {
  // Extract row and column indices
  const [fromRow, fromCol] = move.from;
  const [toRow, toCol] = move.to;

  // Get the pieces
  const piece = getPieceElement(fromRow, fromCol);
  const toCellId = String.fromCharCode('a'.charCodeAt(0) + toCol) + (8 - toRow);
  const toCell = document.getElementById(toCellId);

  // Perform the move
  if (piece && toCell) {
    if (canPromote(piece, toRow)) {
      // Promote pawn to queen
      const queenId = 'q-' + piece.id.slice(-1); // Reuse color from pawn ID, e.g., 'q-w' or 'q-b'
      toCell.innerHTML = currentTurn.color === 'white' ? '&#9813;' : '&#9819;'; // Use appropriate queen symbol
      toCell.firstChild.id = queenId;
    } else if (move.enPassant) {
      // En Passant move, capture enemy pawn
      const enemyRow = currentTurn.color === 'white' ? row + 1 : row - 1;
      const enemyPawn = getPieceElement(enemyRow, toCol);
      if (enemyPawn) {
        enemyPawn.parentElement.innerHTML = ''; // Remove captured pawn
      }
      toCell.innerHTML = piece.outerHTML; // Move capturing pawn
    } else {
      toCell.innerHTML = piece.outerHTML; // Move piece
    }
    piece.parentElement.innerHTML = ''; // Clear original cell
  }

  // Swap turns
  currentTurn.color = currentTurn.color === 'white' ? 'black' : 'white';
}

function makeRandomMove() {
  const legalMoves = calculateLegalMoves();
  if (legalMoves.length === 0) {
    currentTurn.color = currentTurn.color === 'white' ? 'black' : 'white';
    return; // Skip the turn if no legal moves
  }
  const move = legalMoves[Math.floor(Math.random() * legalMoves.length)];
  performMove(move);
}

// Auto-play the game with a random move every 2 seconds
setInterval(makeRandomMove, 2000);
